/* TerraHype rocks, minerals and fossils for the Library 'Rocks' tab.
   regions tags: Igneous, Sedimentary, Metamorphic, Mineral, Fossil (Common = any).
   'art' matches a key in window.SEA_ART. */
window.__SEA_SHELLS__ = [{"name": "Granite", "sci": "Coarse-grained, intrusive", "group": "Igneous rock", "art": "mineral", "regions": ["Igneous"], "size": "Hardness ~6-7", "desc": "Look for a speckled mix of glassy gray quartz, pink or white feldspar and flecks of dark mica. Its large crystals show it cooled slowly deep underground. Common in mountains and used for countertops and monuments."}, {"name": "Basalt", "sci": "Fine-grained, volcanic", "group": "Igneous rock", "art": "mineral", "regions": ["Igneous"], "size": "Hardness ~6", "desc": "A dark, heavy, fine-grained rock whose crystals are too small to see. It forms from fast-cooling lava and makes up most of the ocean floor and many lava plains. Sometimes full of small gas holes."}, {"name": "Obsidian", "sci": "Volcanic glass", "group": "Igneous rock", "art": "mineral", "regions": ["Igneous"], "size": "Hardness ~5-6", "desc": "Shiny black natural glass with sharp, curved edges, formed when lava cooled almost instantly. It has no crystals. Early peoples flaked it into razor-sharp blades and arrowheads."}, {"name": "Pumice", "sci": "Frothy volcanic rock", "group": "Igneous rock", "art": "mineral", "regions": ["Igneous"], "size": "Very low density", "desc": "A pale, gritty rock so full of frozen gas bubbles that it can float on water - the only common rock that does. It forms from frothy lava blasted from a volcano."}, {"name": "Sandstone", "sci": "Cemented sand grains", "group": "Sedimentary rock", "art": "mineral", "regions": ["Sedimentary"], "size": "Hardness ~6-7", "desc": "Made of sand grains you can often see and feel, cemented together. It frequently shows layers or ripple marks and forms many colorful desert cliffs, arches and canyon walls."}, {"name": "Limestone", "sci": "Mostly calcium carbonate", "group": "Sedimentary rock", "art": "mineral", "regions": ["Sedimentary"], "size": "Hardness ~3", "desc": "A pale gray rock built largely from ancient shells and coral. It fizzes when a drop of weak acid touches it, and slowly dissolving limestone forms most of the world's caves."}, {"name": "Shale", "sci": "Hardened mud and clay", "group": "Sedimentary rock", "art": "mineral", "regions": ["Sedimentary"], "size": "Hardness ~3", "desc": "A fine, dull rock that splits into thin flat layers. Formed from compacted mud, it is the most common sedimentary rock and often holds well-preserved fossils."}, {"name": "Conglomerate", "sci": "Cemented pebbles", "group": "Sedimentary rock", "art": "mineral", "regions": ["Sedimentary"], "size": "Varies", "desc": "A natural concrete of rounded pebbles and gravel cemented in finer material. The rounded stones show they were tumbled smooth by water before settling in a riverbed or beach."}, {"name": "Marble", "sci": "Metamorphosed limestone", "group": "Metamorphic rock", "art": "mineral", "regions": ["Metamorphic"], "size": "Hardness ~3", "desc": "A smooth, often swirled stone that began as limestone before heat and pressure recrystallized it. Prized by sculptors, it can be polished to a soft shine and still fizzes in acid."}, {"name": "Slate", "sci": "Metamorphosed shale", "group": "Metamorphic rock", "art": "mineral", "regions": ["Metamorphic"], "size": "Hardness ~3-4", "desc": "A fine, dark gray rock that splits cleanly into flat sheets. Made from shale squeezed by heat and pressure, it was long used for roof tiles and chalkboards."}, {"name": "Gneiss", "sci": "Banded, high-grade", "group": "Metamorphic rock", "art": "mineral", "regions": ["Metamorphic"], "size": "Hardness ~6-7", "desc": "Recognizable by its stripes of light and dark minerals, formed under intense heat and pressure deep in the crust. Some gneiss is among the oldest rock on Earth."}, {"name": "Quartzite", "sci": "Metamorphosed sandstone", "group": "Metamorphic rock", "art": "mineral", "regions": ["Metamorphic"], "size": "Hardness ~7", "desc": "A very hard, often pale rock made when sandstone is baked until its grains fuse. Unlike sandstone it does not crumble, and it resists almost all weathering."}, {"name": "Quartz", "sci": "Silicon dioxide", "group": "Mineral", "art": "mineral", "regions": ["Mineral"], "size": "Hardness 7", "desc": "One of the most common minerals, forming six-sided crystals that come in many colors, including purple amethyst and yellow citrine. It is hard enough to scratch glass."}, {"name": "Feldspar", "sci": "Aluminum silicates", "group": "Mineral", "art": "mineral", "regions": ["Mineral"], "size": "Hardness 6", "desc": "The most abundant mineral group in the crust, usually pink, white or gray with flat, blocky crystals. It makes up much of granite and slowly weathers into clay."}, {"name": "Calcite", "sci": "Calcium carbonate", "group": "Mineral", "art": "mineral", "regions": ["Mineral"], "size": "Hardness 3", "desc": "A soft, often clear or white mineral that fizzes in weak acid. Clear pieces can split light into a double image. It builds limestone and marble and lines many caves."}, {"name": "Pyrite", "sci": "Iron sulfide", "group": "Mineral", "art": "mineral", "regions": ["Mineral"], "size": "Hardness 6-6.5", "desc": "Nicknamed 'fool's gold' for its shiny brassy color, it often grows in striking near-perfect cubes. Unlike real gold it is hard and brittle, and it can spark when struck."}, {"name": "Mica", "sci": "Sheet silicate", "group": "Mineral", "art": "mineral", "regions": ["Mineral"], "size": "Hardness 2-3", "desc": "A mineral that peels into thin, flexible, see-through sheets and adds glitter to many rocks. Tilt a rock in sunlight and the sparkles are often flakes of mica."}, {"name": "Trilobite", "sci": "Extinct arthropod", "group": "Fossil", "art": "fossil", "regions": ["Fossil"], "size": "To ~10 cm", "desc": "A common fossil of a hard-shelled sea animal with a body in three lengthwise lobes. Trilobites thrived for nearly 300 million years before dying out, long before the dinosaurs."}, {"name": "Ammonite", "sci": "Coiled cephalopod", "group": "Fossil", "art": "fossil", "regions": ["Fossil"], "size": "To ~30 cm+", "desc": "A spiral, chambered shell from an ancient relative of squid and the nautilus. Often beautifully ridged and sometimes shimmering, ammonites are prized and widespread fossils."}, {"name": "Petrified wood", "sci": "Mineralized wood", "group": "Fossil", "art": "fossil", "regions": ["Fossil"], "size": "Varies", "desc": "Ancient wood turned to colorful stone, cell by cell, as minerals replaced the original tissue. It can still show growth rings and bark, but it is now hard rock."}];
